  1→import { useRef, useCallback } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const YAW_RATE = 0.035;
 10→const PITCH_RATE = 0.025;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→// ── Docking constants ─────────────────────────────────────────────────
 21→const DOCKING_THRESHOLD_Z = 18;
 22→const DOCKING_CENTER_MAX = 50;
 23→const MAGNET_THRESHOLD_Z = 80;
 24→const MAGNET_STRENGTH = 0.015;
 25→const DOCK_ACCEL = 0.5;
 26→const DOCK_MAX_SPEED = 8;
 27→
 28→/** Max viewZ at which labels start fading in */
 29→export const LABEL_Z_MAX = 800;
 30→
 31→/** Export docking thresholds for external use */
 32→export { MAGNET_THRESHOLD_Z };
 33→
 34→/** Parse "#5f92ff" → { r, g, b } */
 35→const parseHex = (hex) => ({
 36→    r: parseInt(hex.slice(1, 3), 16),
 37→    g: parseInt(hex.slice(3, 5), 16),
 38→    b: parseInt(hex.slice(5, 7), 16),
 39→});
 40→
 41→/** Seeded pseudo-random from integer seed */
 42→const seededRandom = (seed) => {
 43→    let s = seed | 0;
 44→    return () => {
 45→        s = (s * 1664525 + 1013904223) | 0;
 46→        return ((s >>> 0) / 4294967296);
 47→    };
 48→};
 49→
 50→/** Get forward direction vector from yaw + pitch */
 51→const getForwardVector = (yaw, pitch) => ({
 52→    x: Math.sin(yaw) * Math.cos(pitch),
 53→    y: Math.sin(pitch),
 54→    z: Math.cos(yaw) * Math.cos(pitch),
 55→});
 56→
 57→const useRocketMode = () => {
 58→    const isActiveRef = useRef(false);
 59→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 60→    const yawRef = useRef(0);
 61→    const pitchRef = useRef(0);
 62→    const velocityRef = useRef(0);
 63→    const starsRef = useRef([]);
 64→    const sortedIndicesRef = useRef([]);
 65→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 66→    const targetIndexRef = useRef(-1);
 67→    const frameRef = useRef(0);
 68→    const layerRef = useRef(null);
 69→    const rafRef = useRef(null);
 70→    const stageSizeRef = useRef({ width: 0, height: 0 });
 71→    const onKeyDownRef = useRef(null);
 72→    const onKeyUpRef = useRef(null);
 73→
 74→    // ── Docking refs ──────────────────────────────────────────────────
 75→    const dockingStateRef = useRef('none'); // 'none' | 'magnet' | 'approaching' | 'flash' | 'done'
 76→    const dockingTargetIdxRef = useRef(-1);
 77→    const dockingProgressRef = useRef(0);
 78→    const dockingStartTimeRef = useRef(0);
 79→    const dockingCallbackRef = useRef(null);
 80→    const inputFrozenRef = useRef(false);
 81→    const dockingStarScaleRef = useRef(1);
 82→    const dockCooldownRef = useRef(0); // timestamp — suppress auto-dock until this time
 83→    const galaxyCenterRef = useRef({ x: 0, y: 0 });
 84→
 85→    const sortStars = useCallback(() => {
 86→        const stars = starsRef.current;
 87→        const indices = sortedIndicesRef.current;
 88→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 89→        for (let i = 1; i < indices.length; i++) {
 90→            const key = indices[i];
 91→            let j = i - 1;
 92→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 93→                indices[j + 1] = indices[j];
 94→                j--;
 95→            }
 96→            indices[j + 1] = key;
 97→        }
 98→    }, []);
 99→
100→    const tick = useCallback(() => {
101→        if (!isActiveRef.current) return;
102→
103→        const keys = keysRef.current;
104→        const cam = camPosRef.current;
105→        const stars = starsRef.current;
106→        const size = stageSizeRef.current;
107→        const dockState = dockingStateRef.current;
108→
109→        // ── Input processing (frozen during docking) ──────────────────
110→        if (!inputFrozenRef.current) {
111→            // ── Yaw (A/D) ─────────────────────────────────────────────
112→            if (keys.a) yawRef.current -= YAW_RATE;
113→            if (keys.d) yawRef.current += YAW_RATE;
114→
115→            // ── Pitch (Q/E), clamped ──────────────────────────────────
116→            if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
117→            if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
118→
119→            // ── Velocity ──────────────────────────────────────────────
120→            if (keys.w) {
121→                velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
122→            } else if (keys.s) {
123→                velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
124→            } else {
125→                velocityRef.current *= FRICTION;
126→                if (velocityRef.current < 0.01) velocityRef.current = 0;
127→            }
128→        }
129→
130→        // ── Magnetic pull (auto-aim toward docking target) ────────────
131→        if (dockState === 'magnet') {
132→            const tidx = dockingTargetIdxRef.current;
133→            if (tidx >= 0 && tidx < stars.length) {
134→                const target = stars[tidx];
135→                const relX = target.worldX - cam.x;
136→                const relY = target.worldY - cam.y;
137→                const relZ = target.worldZ - cam.z;
138→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
139→                if (dist3D > 0.01) {
140→                    const desiredYaw = Math.atan2(relX, relZ);
141→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
142→                    // Proximity factor: 0 at MAGNET_THRESHOLD_Z, 1 at DOCKING_THRESHOLD_Z
143→                    const proximityFactor = Math.max(0, Math.min(1,
144→                        (MAGNET_THRESHOLD_Z - target.viewZ) / (MAGNET_THRESHOLD_Z - DOCKING_THRESHOLD_Z)
145→                    ));
146→                    const lerpFactor = MAGNET_STRENGTH * (0.3 + proximityFactor * 0.7);
147→                    // Normalize yaw difference to [-PI, PI]
148→                    let yawDiff = desiredYaw - yawRef.current;
149→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
150→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
151→                    yawRef.current += yawDiff * lerpFactor;
152→                    pitchRef.current += (desiredPitch - pitchRef.current) * lerpFactor;
153→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
154→                }
155→                // Disengage if target drifts beyond magnet zone
156→                if (target.viewZ > MAGNET_THRESHOLD_Z * 1.2 || target.viewZ < TARGET_Z_MIN) {
157→                    dockingStateRef.current = 'none';
158→                    dockingTargetIdxRef.current = -1;
159→                }
160→            }
161→        }
162→
163→        // ── Docking animation sequence ────────────────────────────────
164→        if (dockState === 'approaching' || dockState === 'flash') {
165→            const elapsed = performance.now() - dockingStartTimeRef.current;
166→            const tidx = dockingTargetIdxRef.current;
167→            const target = tidx >= 0 && tidx < stars.length ? stars[tidx] : null;
168→
169→            if (elapsed < 800 && target) {
170→                // Phase 1: Auto-approach (0-800ms)
171→                const relX = target.worldX - cam.x;
172→                const relY = target.worldY - cam.y;
173→                const relZ = target.worldZ - cam.z;
174→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
175→                if (dist3D > 0.01) {
176→                    const desiredYaw = Math.atan2(relX, relZ);
177→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
178→                    let yawDiff = desiredYaw - yawRef.current;
179→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
180→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
181→                    yawRef.current += yawDiff * 0.12;
182→                    pitchRef.current += (desiredPitch - pitchRef.current) * 0.12;
183→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
184→                }
185→                velocityRef.current = Math.min(velocityRef.current + DOCK_ACCEL, DOCK_MAX_SPEED);
186→                // Quadratic ease-in scale: 1 → 9
187→                const t1 = elapsed / 800;
188→                dockingStarScaleRef.current = 1 + 8 * t1 * t1;
189→                dockingProgressRef.current = t1 * 0.6;
190→            } else if (elapsed < 1200 && target) {
191→                // Phase 2: Star explosion (800-1200ms)
192→                velocityRef.current *= 0.9;
193→                const t2 = (elapsed - 800) / 400;
194→                // Ease-out scale: 9 → 50
195→                const easeOut = 1 - (1 - t2) * (1 - t2);
196→                dockingStarScaleRef.current = 9 + 41 * easeOut;
197→                dockingProgressRef.current = 0.6 + t2 * 0.3;
198→            } else if (elapsed < 1700) {
199→                // Phase 3: White flash (1200-1700ms)
200→                velocityRef.current = 0;
201→                dockingStateRef.current = 'flash';
202→                const t3 = (elapsed - 1200) / 500;
203→                dockingProgressRef.current = 0.9 + t3 * 0.1;
204→            } else {
205→                // Done — stop loop immediately, then trigger callback exactly once
206→                isActiveRef.current = false;
207→                if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
208→                dockingStateRef.current = 'done';
209→                dockingProgressRef.current = 1;
210→                const cb = dockingCallbackRef.current;
211→                dockingCallbackRef.current = null;
212→                if (cb) cb();
213→                return; // do not reschedule
214→            }
215→        }
216→
217→        const yaw = yawRef.current;
218→        const pitch = pitchRef.current;
219→        const velocity = velocityRef.current;
220→
221→        // ── Position (move along forward vector) ─────────────────────
222→        const fwd = getForwardVector(yaw, pitch);
223→        cam.x += fwd.x * velocity;
224→        cam.y += fwd.y * velocity;
225→        cam.z += fwd.z * velocity;
226→
227→        // ── Pre-compute trig for view transform ──────────────────────
228→        const cosYaw = Math.cos(-yaw);
229→        const sinYaw = Math.sin(-yaw);
230→        const cosPitch = Math.cos(pitch);
231→        const sinPitch = Math.sin(pitch);
232→
233→        // ── View transform + recycling ───────────────────────────────
234→        const dockingActive = dockState !== 'none';
235→        const protectedIdx = dockingTargetIdxRef.current;
236→        for (let i = 0; i < stars.length; i++) {
237→            const star = stars[i];
238→
239→            // Translate to camera-relative
240→            const relX = star.worldX - cam.x;
241→            const relY = star.worldY - cam.y;
242→            const relZ = star.worldZ - cam.z;
243→
244→            // Yaw rotation (around Y axis)
245→            const rotX1 = relX * cosYaw + relZ * sinYaw;
246→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
247→
248→            // Pitch rotation (around X axis)
249→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
250→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
251→
252→            // Cache on star for renderer
253→            star._rotX1 = rotX1;
254→            star._rotY2 = rotY2;
255→            star.viewZ = viewZ;
256→
257→            // Recycle stars that are behind camera or too far
258→            // Skip recycling for the docking target star
259→            if ((viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) && !(dockingActive && i === protectedIdx)) {
260→                // Respawn ahead of camera using forward vector + random spread
261→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
262→                const spreadX = (Math.random() - 0.5) * 2000;
263→                const spreadY = (Math.random() - 0.5) * 2000;
264→                star.worldX = cam.x + fwd.x * dist + spreadX;
265→                star.worldY = cam.y + fwd.y * dist + spreadY;
266→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
267→
268→                // Recompute view-space for the recycled position
269→                const rX = star.worldX - cam.x;
270→                const rY = star.worldY - cam.y;
271→                const rZ = star.worldZ - cam.z;
272→                const rX1 = rX * cosYaw + rZ * sinYaw;
273→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
274→                star._rotX1 = rX1;
275→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
276→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
277→            }
278→        }
279→
280→        // ── Sort (every N frames) ────────────────────────────────────
281→        frameRef.current++;
282→        if (frameRef.current % SORT_INTERVAL === 0) {
283→            sortStars();
284→        }
285→
286→        // ── Target detection ─────────────────────────────────────────
287→        const cx = size.width / 2;
288→        const cy = size.height / 2;
289→        const focalLength = size.width * 0.6;
290→        let bestIdx = -1;
291→        let bestDist = TARGET_DIST_MAX;
292→
293→        for (let i = 0; i < stars.length; i++) {
294→            const star = stars[i];
295→            if (star.viewZ < TARGET_Z_MIN) continue;
296→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
297→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
298→            const dx = projX - cx;
299→            const dy = projY - cy;
300→            const dist = Math.sqrt(dx * dx + dy * dy);
301→            if (dist < bestDist) {
302→                bestDist = dist;
303→                bestIdx = i;
304→            }
305→        }
306→        targetIndexRef.current = bestIdx;
307→
308→        // ── Docking detection ─────────────────────────────────────────
309→        // Read live ref (not stale snapshot) to respect triggerDocking() calls from user input
310→        const cooldownActive = performance.now() < dockCooldownRef.current;
311→        if (dockingStateRef.current === 'none' && bestIdx >= 0 && !cooldownActive) {
312→            const targetStar = stars[bestIdx];
313→            const viewZ = targetStar.viewZ;
314→            if (viewZ < DOCKING_THRESHOLD_Z && bestDist < DOCKING_CENTER_MAX) {
315→                // Close enough and centered — auto-dock
316→                dockingStateRef.current = 'approaching';
317→                dockingTargetIdxRef.current = bestIdx;
318→                dockingStartTimeRef.current = performance.now();
319→                dockingProgressRef.current = 0;
320→                dockingStarScaleRef.current = 1;
321→                inputFrozenRef.current = true;
322→            } else if (viewZ < MAGNET_THRESHOLD_Z && viewZ > DOCKING_THRESHOLD_Z) {
323→                // In magnet zone — engage gentle pull
324→                dockingStateRef.current = 'magnet';
325→                dockingTargetIdxRef.current = bestIdx;
326→            }
327→        }
328→        // Disengage magnet if best target changes
329→        if (dockingStateRef.current === 'magnet' && bestIdx !== dockingTargetIdxRef.current) {
330→            dockingStateRef.current = 'none';
331→            dockingTargetIdxRef.current = -1;
332→        }
333→
334→        // ── Redraw ───────────────────────────────────────────────────
335→        if (layerRef.current) {
336→            layerRef.current.batchDraw();
337→        }
338→
339→        rafRef.current = requestAnimationFrame(tick);
340→    }, [sortStars]);
341→
342→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
343→        // Clean up any existing loop/listeners before re-entering
344→        isActiveRef.current = false;
345→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
346→        if (onKeyDownRef.current) {
347→            window.removeEventListener('keydown', onKeyDownRef.current);
348→            window.removeEventListener('keyup', onKeyUpRef.current);
349→            onKeyDownRef.current = null; onKeyUpRef.current = null;
350→        }
351→
352→        stageSizeRef.current = stageSize;
353→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
354→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
355→        yawRef.current = 0;
356→        pitchRef.current = 0;
357→        velocityRef.current = 0;
358→        frameRef.current = 0;
359→        targetIndexRef.current = -1;
360→
361→        // Reset docking state
362→        dockingStateRef.current = 'none';
363→        dockingTargetIdxRef.current = -1;
364→        dockingProgressRef.current = 0;
365→        dockingStarScaleRef.current = 1;
366→        inputFrozenRef.current = false;
367→        dockCooldownRef.current = 0;
368→
369→        // Build star array from posts — distributed in 3D volume
370→        const stars = [];
371→        for (let i = 0; i < galaxyPosts.length; i++) {
372→            const post = galaxyPosts[i];
373→            const uid = post.users?.id ?? post.user_id;
374→            const likeCount = post.like_count != null
375→                ? post.like_count
376→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
377→                    ? post.likes[0].count : 0);
378→            const color = getStarColor(uid);
379→            const rng = seededRandom(simpleHash(post.id || String(i)));
380→            stars.push({
381→                postId: post.id,
382→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
383→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
384→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
385→                viewZ: 0,
386→                _rotX1: 0,
387→                _rotY2: 0,
388→                color,
389→                colorRgb: parseHex(color),
390→                radius: getStarRadius(likeCount),
391→                title: post.title || 'Untitled',
392→                authorName: post.users?.name || post.user_name || 'Anonymous',
393→                post,
394→            });
395→        }
396→
397→        starsRef.current = stars;
398→
399→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
400→        const indices = new Array(stars.length);
401→        for (let i = 0; i < stars.length; i++) indices[i] = i;
402→        sortedIndicesRef.current = indices;
403→
404→        // Key listeners
405→        const onKeyDown = (e) => {
406→            const key = e.key.toLowerCase();
407→            if (key === 'w') keysRef.current.w = true;
408→            if (key === 's') keysRef.current.s = true;
409→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
410→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
411→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
412→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
413→        };
414→        const onKeyUp = (e) => {
415→            const key = e.key.toLowerCase();
416→            if (key === 'w') keysRef.current.w = false;
417→            if (key === 's') keysRef.current.s = false;
418→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
419→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
420→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
421→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
422→        };
423→
424→        onKeyDownRef.current = onKeyDown;
425→        onKeyUpRef.current = onKeyUp;
426→        window.addEventListener('keydown', onKeyDown);
427→        window.addEventListener('keyup', onKeyUp);
428→
429→        // Reset keys
430→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
431→        isActiveRef.current = true;
432→
433→        // Start rAF
434→        rafRef.current = requestAnimationFrame(tick);
435→    }, [tick]);
436→
437→    const exit = useCallback(() => {
438→        isActiveRef.current = false;
439→        if (rafRef.current) {
440→            cancelAnimationFrame(rafRef.current);
441→            rafRef.current = null;
442→        }
443→        // Remove key listeners
444→        if (onKeyDownRef.current) {
445→            window.removeEventListener('keydown', onKeyDownRef.current);
446→            window.removeEventListener('keyup', onKeyUpRef.current);
447→            onKeyDownRef.current = null;
448→            onKeyUpRef.current = null;
449→        }
450→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
451→        // Reset docking
452→        dockingStateRef.current = 'none';
453→        dockingTargetIdxRef.current = -1;
454→        dockingProgressRef.current = 0;
455→        dockingStarScaleRef.current = 1;
456→        inputFrozenRef.current = false;
457→        dockingCallbackRef.current = null;
458→    }, []);
459→
460→    const project = useCallback((star, cx, cy) => {
461→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
462→
463→        const stageWidth = stageSizeRef.current.width;
464→        const focalLength = stageWidth * 0.6; // ~80° FOV
465→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
466→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
467→        const scale = focalLength / star.viewZ;
468→
469→        return { projX, projY, scale };
470→    }, []);
471→
472→    const getTargetedPost = useCallback(() => {
473→        const idx = targetIndexRef.current;
474→        if (idx < 0 || idx >= starsRef.current.length) return null;
475→        return starsRef.current[idx].post;
476→    }, []);
477→
478→    const getSpeedRatio = useCallback(() => {
479→        return velocityRef.current / MAX_SPEED;
480→    }, []);
481→
482→    const getDockingState = useCallback(() => {
483→        return dockingStateRef.current;
484→    }, []);
485→
486→    const getSessionSnapshot = useCallback(() => {
487→        const cam = camPosRef.current;
488→        const gc = galaxyCenterRef.current;
489→        // Back up camera along reverse forward vector so restore doesn't land inside the star
490→        const RESTORE_BACK_OFFSET = 60;
491→        const fwd = getForwardVector(yawRef.current, pitchRef.current);
492→        return {
493→            camX: cam.x - fwd.x * RESTORE_BACK_OFFSET,
494→            camY: cam.y - fwd.y * RESTORE_BACK_OFFSET,
495→            camZ: cam.z - fwd.z * RESTORE_BACK_OFFSET,
496→            yaw: yawRef.current,
497→            pitch: pitchRef.current,
498→            velocity: 0,
499→            galaxyCenterX: gc.x,
500→            galaxyCenterY: gc.y,
501→            timestamp: Date.now(),
502→        };
503→    }, []);
504→
505→    const restoreFromSnapshot = useCallback((snapshot, galaxyPosts, stageSize) => {
506→        // Clean up any existing loop/listeners before restoring
507→        isActiveRef.current = false;
508→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
509→        if (onKeyDownRef.current) {
510→            window.removeEventListener('keydown', onKeyDownRef.current);
511→            window.removeEventListener('keyup', onKeyUpRef.current);
512→            onKeyDownRef.current = null; onKeyUpRef.current = null;
513→        }
514→
515→        stageSizeRef.current = stageSize;
516→        camPosRef.current = { x: snapshot.camX, y: snapshot.camY, z: snapshot.camZ };
517→        yawRef.current = snapshot.yaw;
518→        pitchRef.current = snapshot.pitch;
519→        velocityRef.current = 0; // smooth re-entry
520→        frameRef.current = 0;
521→        targetIndexRef.current = -1;
522→
523→        // Reset docking state
524→        dockingStateRef.current = 'none';
525→        dockingTargetIdxRef.current = -1;
526→        dockingProgressRef.current = 0;
527→        dockingStarScaleRef.current = 1;
528→        inputFrozenRef.current = false;
529→        // Suppress auto-dock for 2s after restore to prevent redirect loop
530→        dockCooldownRef.current = performance.now() + 2000;
531→
532→        // Build star array — use stored galaxy center for consistent star placement
533→        const galaxyCenter = snapshot.galaxyCenterX != null
534→            ? { x: snapshot.galaxyCenterX, y: snapshot.galaxyCenterY }
535→            : { x: snapshot.camX, y: snapshot.camY };
536→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
537→        const stars = [];
538→        for (let i = 0; i < galaxyPosts.length; i++) {
539→            const post = galaxyPosts[i];
540→            const uid = post.users?.id ?? post.user_id;
541→            const likeCount = post.like_count != null
542→                ? post.like_count
543→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
544→                    ? post.likes[0].count : 0);
545→            const color = getStarColor(uid);
546→            const rng = seededRandom(simpleHash(post.id || String(i)));
547→            stars.push({
548→                postId: post.id,
549→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
550→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
551→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2,
552→                viewZ: 0,
553→                _rotX1: 0,
554→                _rotY2: 0,
555→                color,
556→                colorRgb: parseHex(color),
557→                radius: getStarRadius(likeCount),
558→                title: post.title || 'Untitled',
559→                authorName: post.users?.name || post.user_name || 'Anonymous',
560→                post,
561→            });
562→        }
563→
564→        starsRef.current = stars;
565→
566→        const indices = new Array(stars.length);
567→        for (let i = 0; i < stars.length; i++) indices[i] = i;
568→        sortedIndicesRef.current = indices;
569→
570→        // Key listeners
571→        const onKeyDown = (e) => {
572→            const key = e.key.toLowerCase();
573→            if (key === 'w') keysRef.current.w = true;
574→            if (key === 's') keysRef.current.s = true;
575→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
576→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
577→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
578→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
579→        };
580→        const onKeyUp = (e) => {
581→            const key = e.key.toLowerCase();
582→            if (key === 'w') keysRef.current.w = false;
583→            if (key === 's') keysRef.current.s = false;
584→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
585→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
586→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
587→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
588→        };
589→
590→        onKeyDownRef.current = onKeyDown;
591→        onKeyUpRef.current = onKeyUp;
592→        window.addEventListener('keydown', onKeyDown);
593→        window.addEventListener('keyup', onKeyUp);
594→
595→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
596→        isActiveRef.current = true;
597→
598→        rafRef.current = requestAnimationFrame(tick);
599→    }, [tick]);
600→
601→    const setDockingCallback = useCallback((cb) => {
602→        // Don't overwrite a callback that's already mid-animation
603→        const state = dockingStateRef.current;
604→        if (state === 'none' || state === 'magnet') {
605→            dockingCallbackRef.current = cb;
606→        }
607→    }, []);
608→
609→    const abortDocking = useCallback(() => {
610→        if (dockingStateRef.current === 'magnet') {
611→            dockingStateRef.current = 'none';
612→            dockingTargetIdxRef.current = -1;
613→            dockingProgressRef.current = 0;
614→            dockingStarScaleRef.current = 1;
615→        }
616→        // Approaching/flash are non-interruptible
617→    }, []);
618→
619→    const triggerDocking = useCallback((targetIdx, callback) => {
620→        if (dockingStateRef.current !== 'none' && dockingStateRef.current !== 'magnet') return;
621→        dockingStateRef.current = 'approaching';
622→        dockingTargetIdxRef.current = targetIdx;
623→        dockingStartTimeRef.current = performance.now();
624→        dockingProgressRef.current = 0;
625→        dockingStarScaleRef.current = 1;
626→        inputFrozenRef.current = true;
627→        if (callback) dockingCallbackRef.current = callback;
628→    }, []);
629→
630→    return {
631→        enter,
632→        exit,
633→        layerRef,
634→        starsRef,
635→        sortedIndicesRef,
636→        rocketPos: camPosRef,
637→        heading: yawRef,
638→        pitch: pitchRef,
639→        velocity: velocityRef,
640→        targetIndexRef,
641→        stageSizeRef,
642→        project,
643→        isActive: isActiveRef,
644→        getTargetedPost,
645→        getSpeedRatio,
646→        // Docking API
647→        getDockingState,
648→        getSessionSnapshot,
649→        restoreFromSnapshot,
650→        setDockingCallback,
651→        abortDocking,
652→        triggerDocking,
653→        dockingStateRef,
654→        dockingTargetIdxRef,
655→        dockingProgressRef,
656→        dockingStarScaleRef,
657→        inputFrozenRef,
658→    };
659→};
660→
661→export default useRocketMode;
